//! https://github.com/allyourcodebase/binutils/blob/master/build.zig
const std = @import("std");

pub fn configHeader(
    b: *std.Build,
    style: std.Build.Step.ConfigHeader.Style,
    target: std.Build.ResolvedTarget,
    comptime version_str: []const u8,
) *std.Build.Step.ConfigHeader {
    return b.addConfigHeader(.{ .style = style }, .{
        .ENABLE_CHECKING = null,
        .ENABLE_NLS = if (target.result.os.tag == .linux) true else null,
        .HAVE_CFLOCALECOPYPREFERREDLANGUAGES = null,
        .HAVE_CFPREFERENCESCOPYAPPVALUE = null,
        .HAVE_DCGETTEXT = if (target.result.os.tag == .linux) true else null,
        .HAVE_DECL_BASENAME = target.result.isGnuLibC(),
        .HAVE_DECL_STPCPY = true,
        .HAVE_DLFCN_H = true,
        .HAVE_GETTEXT = if (target.result.os.tag == .linux) true else null,
        .HAVE_ICONV = switch (target.result.os.tag) {
            .wasi, .freebsd, .netbsd => true,
            else => null,
        },
        .HAVE_INTTYPES_H = true,
        .HAVE_MEMORY_H = true,
        .HAVE_SIGSETJMP = if (target.result.os.tag == .wasi) null else true,
        .HAVE_STDINT_H = true,
        .HAVE_STDLIB_H = true,
        .HAVE_STRINGS_H = true,
        .HAVE_STRING_H = true,
        .HAVE_SYS_STAT_H = true,
        .HAVE_SYS_TYPES_H = true,
        .HAVE_UNISTD_H = true,
        .LT_OBJDIR = ".libs/",
        .PACKAGE = "opcodes",
        .PACKAGE_BUGREPORT = "",
        .PACKAGE_NAME = "opcodes",
        .PACKAGE_STRING = "opcodes " ++ version_str,
        .PACKAGE_TARNAME = "opcodes",
        .PACKAGE_URL = "",
        .PACKAGE_VERSION = version_str,
        .STDC_HEADERS = true,
        ._ALL_SOURCE = true,
        ._GNU_SOURCE = true,
        ._POSIX_PTHREAD_SEMANTICS = true,
        ._TANDEM_SOURCE = true,
        .__EXTENSIONS__ = true,
        .VERSION = version_str,
        ._MINIX = null,
        ._POSIX_1_SOURCE = null,
        ._POSIX_SOURCE = null,
    });
}

